import{_ as l,o as a,c as i,ak as e}from"./chunks/framework.571fwNe4.js";const M=JSON.parse('{"title":"SR5E1x 微控制器参考手册总结","description":"","frontmatter":{},"headers":[],"relativePath":"技术/参考书籍/embedded/Stellar 32 E系列/参考手册/readme.md","filePath":"技术/参考书籍/embedded/Stellar 32 E系列/参考手册/readme.md"}'),t={name:"技术/参考书籍/embedded/Stellar 32 E系列/参考手册/readme.md"};function n(o,r,s,h,g,d){return a(),i("div",null,[...r[0]||(r[0]=[e('<p>该文档主要围绕 SR5E1x 微控制器的功能、架构、配置、复位与启动等方面进行详细说明，包括其核心模块、系统模块、模拟模块、定时器、通信接口、安全模块等的配置和功能描述，以及复位序列、设备配置格式记录、电源管理、安全性、调试支持等内容，但未涉及 PCB 图的信息。 主要是通讯和模块</p><h1 id="sr5e1x-微控制器参考手册总结" tabindex="-1">SR5E1x 微控制器参考手册总结 <a class="header-anchor" href="#sr5e1x-微控制器参考手册总结" aria-label="Permalink to “SR5E1x 微控制器参考手册总结”">​</a></h1><h2 id="一、文档概述" tabindex="-1">一、文档概述 <a class="header-anchor" href="#一、文档概述" aria-label="Permalink to “一、文档概述”">​</a></h2><ul><li><strong>文档目的</strong>：定义SR5E1x微控制器的功能，供软硬件开发者使用，该芯片基于Arm架构，专为电动汽车应用设计。</li><li><strong>适用人群</strong>：系统软件、硬件开发者和应用程序员，需具备操作系统、微处理器系统设计等相关知识。</li><li><strong>应用场景</strong>：包括车载充电器、DC/DC转换器、牵引逆变器、高级控制电机等电动汽车相关领域。</li></ul><h2 id="二、总体架构与核心" tabindex="-1">二、总体架构与核心 <a class="header-anchor" href="#二、总体架构与核心" aria-label="Permalink to “二、总体架构与核心”">​</a></h2><h3 id="_2-1-架构组成" tabindex="-1">2.1 架构组成 <a class="header-anchor" href="#_2-1-架构组成" aria-label="Permalink to “2.1 架构组成”">​</a></h3><ul><li><strong>核心模块</strong>：包含2个Arm® Cortex®-M7核心（可工作在分离或锁步模式）和1个Arm® Cortex®-M0+核心（位于硬件安全模块HSM）。 <ul><li>Cortex®-M7：具备六阶段双发射流水线、动态分支预测、哈佛架构等，支持DSP指令和单/双精度FPU。</li><li>Cortex®-M0+：低功耗处理器，适用于深度嵌入式应用，具有低门数、低中断延迟等特点。</li></ul></li><li><strong>内存层次结构</strong>：包括各核心私有内存（指令缓存、数据缓存、TCM）和系统RAM，TCM提供快速且确定的SRAM访问。</li></ul><h3 id="_2-2-主要特性" tabindex="-1">2.2 主要特性 <a class="header-anchor" href="#_2-2-主要特性" aria-label="Permalink to “2.2 主要特性”">​</a></h3><ul><li><strong>性能</strong>：2个Cortex®-M7核心最高运行频率306.7MHz，可达1284 DMIPS/2.14 DMIPS/MHz/核心。</li><li><strong>安全性</strong>：硬件安全模块（HSM）基于Cortex®-M0+，支持EVITA medium，具备对称加密硬件加速器等。</li><li><strong>安全性措施</strong>：全面的ASIL-D安全概念，包括FCCU、MEMU、CRC单元等。</li><li><strong>存储</strong>：最高2MB片上闪存（支持读同时写）、96KB数据闪存、488KB片上通用SRAM等。</li><li><strong>外设</strong>：包含多种定时器、增强型ADC系统、DAC、比较器、通信接口等。</li></ul><h2 id="三、系统与内存概述" tabindex="-1">三、系统与内存概述 <a class="header-anchor" href="#三、系统与内存概述" aria-label="Permalink to “三、系统与内存概述”">​</a></h2><h3 id="_3-1-系统架构" tabindex="-1">3.1 系统架构 <a class="header-anchor" href="#_3-1-系统架构" aria-label="Permalink to “3.1 系统架构”">​</a></h3><ul><li><strong>总线矩阵</strong>：基于NIC400，连接多个主设备和从设备，采用带QoS能力的轮询算法仲裁，支持并发访问。</li><li><strong>TCM总线</strong>：DTCM和ITCM通过专用总线直接连接到Cortex®-M7核心，DMA控制器可通过特定总线访问。</li><li><strong>CPU总线</strong>：Cortex®-M7使用多种总线访问不同内存和外设，如64位AXIM总线访问内存和HRTIMs外设等。</li><li><strong>总线主设备外设</strong>：DMA控制器和HSM等通过相应总线接口连接到AXI总线矩阵。</li></ul><h3 id="_3-2-内存组织" tabindex="-1">3.2 内存组织 <a class="header-anchor" href="#_3-2-内存组织" aria-label="Permalink to “3.2 内存组织”">​</a></h3><ul><li><strong>内存映射</strong>：详细定义了不同内存区域的起始和结束地址，包括闪存、SRAM、外设、CoreSight™组件等。</li><li><strong>嵌入式SRAM</strong>：包括256KB系统SRAM、128KB数据TCM RAM、64KB指令TCM RAM，系统AXI SRAM可按多种单位访问。</li><li><strong>闪存概述</strong>：作为非易失性内存，分为两个主内存块和一个信息块，由闪存控制器管理。</li></ul><h2 id="四、设备配置" tabindex="-1">四、设备配置 <a class="header-anchor" href="#四、设备配置" aria-label="Permalink to “四、设备配置”">​</a></h2><h3 id="_4-1-核心模块配置" tabindex="-1">4.1 核心模块配置 <a class="header-anchor" href="#_4-1-核心模块配置" aria-label="Permalink to “4.1 核心模块配置”">​</a></h3><ul><li>两个Cortex®-M7核心（Core1和Core2）可配置为分离模式（提供两个处理单元）或锁步模式（提供一个处理单元），均具备单/双精度FPU和16个核心内存保护单元区域。</li></ul><h3 id="_4-2-系统模块配置" tabindex="-1">4.2 系统模块配置 <a class="header-anchor" href="#_4-2-系统模块配置" aria-label="Permalink to “4.2 系统模块配置”">​</a></h3><ul><li><strong>互连/总线矩阵</strong>：支持QoS配置，可通过DCF记录设置各启动器的读写通道优先级，采用E2E ECC等安全机制检测数据路径 corruption。</li><li><strong>硬件信号量（HSEM2）</strong>：提供32个基于寄存器的信号量，支持多核心系统中的同步。</li><li><strong>系统内存保护单元（SMPU）</strong>：包含24个区域，定义了主设备ID分配。</li><li><strong>嵌套向量中断控制器（NVIC）</strong>：每个CPU有自己的NVIC，可处理多种异常和中断，支持核心间的中断和唤醒。</li><li><strong>DMA控制器与多路复用器</strong>：2个DMA实例（各8个输入流）和1个DMAMUX，支持多种模式和配置。</li><li><strong>GPIO配置</strong>：IO组织为多个16位端口，支持多种配置和功能。</li></ul><h3 id="_4-3-模拟模块配置" tabindex="-1">4.3 模拟模块配置 <a class="header-anchor" href="#_4-3-模拟模块配置" aria-label="Permalink to “4.3 模拟模块配置”">​</a></h3><ul><li><strong>温度传感器</strong>：可测量芯片温度，输出模拟电压和数字信号，校准参数存储在UTEST闪存中。</li><li><strong>ADCx</strong>：输入连接外部通道和内部源，支持多种触发选择。</li><li><strong>SDADC</strong>：两个独立的16位Sigma-Delta ADC，支持多种输入模式和触发方式。</li><li><strong>DAC</strong>：包含五个DAC模块，其中一个为B-DAC提供输出缓冲，其余为内部连接。</li><li><strong>比较器</strong>：8个模拟比较器，分为两组，每组4个。</li></ul><h3 id="_4-4-定时器配置" tabindex="-1">4.4 定时器配置 <a class="header-anchor" href="#_4-4-定时器配置" aria-label="Permalink to “4.4 定时器配置”">​</a></h3><ul><li><strong>HRTIMx</strong>：两个高分辨率定时器实例，时钟频率为系统时钟，支持多种外部事件映射、故障输入等。</li><li><strong>其他定时器</strong>：包括TIM1/TIM8、TIM2/TIM3/TIM4/TIM5、TIM15/TIM16等，各有不同的分辨率、通道数和功能。</li><li><strong>看门狗</strong>：两个独立看门狗（IWDG1和IWDG2）和两个窗口看门狗（WWDG1和WWDG2）。</li><li><strong>RTC</strong>：独立的BCD定时器/计数器，可用于长时间间隔计数，时钟源可配置。</li></ul><h3 id="_4-5-通信接口配置" tabindex="-1">4.5 通信接口配置 <a class="header-anchor" href="#_4-5-通信接口配置" aria-label="Permalink to “4.5 通信接口配置”">​</a></h3><ul><li><strong>CAN子系统</strong>：参考相关章节。</li><li><strong>SPI</strong>：四个SPI/I2S模块，部分支持I2S协议，连接不同总线并由相应时钟驱动。</li><li><strong>UART</strong>：三个UART模块，支持LIN协议，接收不同时钟信号。</li><li><strong>I2C</strong>：两个I2C模块，连接APB1总线，接收两种时钟。</li></ul><h3 id="_4-6-安全模块配置" tabindex="-1">4.6 安全模块配置 <a class="header-anchor" href="#_4-6-安全模块配置" aria-label="Permalink to “4.6 安全模块配置”">​</a></h3><ul><li><strong>CRC</strong>：一个CRC模块，连接AHB1桥，接收AHB时钟。</li><li><strong>MEMU2</strong>：管理内存错误，包括系统RAM、外设RAM和闪存的错误源和报告表。</li><li><strong>IMA</strong>：支持系统开发和测试期间内存数据值的修改，可访问特定SRAM阵列。</li><li><strong>FCCU</strong>：负责故障收集和控制，有多种输入输出信号，支持不同的故障处理反应。</li><li><strong>CEM</strong>：15个CEM实例，每个实例有一个组。</li><li><strong>REG_PROT</strong>：AHB和APB桥包含寄存器保护机制，防止意外修改。</li><li><strong>STCU</strong>：包含CBIST和MBIST相关配置。</li><li><strong>ECC</strong>：用于端到端保护和外设RAM保护，不同内存有不同的ECC实现。</li></ul><h2 id="五、复位与启动" tabindex="-1">五、复位与启动 <a class="header-anchor" href="#五、复位与启动" aria-label="Permalink to “五、复位与启动”">​</a></h2><h3 id="_5-1-相关模块" tabindex="-1">5.1 相关模块 <a class="header-anchor" href="#_5-1-相关模块" aria-label="Permalink to “5.1 相关模块”">​</a></h3><ul><li>包括电源管理控制器（PMC）、复位和时钟控制模块（RCC）、系统状态和配置模块（SSCM）、自测试控制单元（STCU3）。</li></ul><h3 id="_5-2-复位序列" tabindex="-1">5.2 复位序列 <a class="header-anchor" href="#_5-2-复位序列" aria-label="Permalink to “5.2 复位序列”">​</a></h3><ul><li><strong>电源-up阶段</strong>：PMC监控电源，稳定后向RCC发送信号进入PHASE0。</li><li><strong>PHASE0</strong>：初始化模拟电源，重置数字模块等，完成后进入PHASE1[DEST]。</li><li><strong>其他阶段</strong>：包括PHASE1[DEST]、PHASE2[DEST]、PHASE3[DEST]、IDLE[DEST]以及功能复位相关阶段，各阶段有不同的操作和退出条件。</li><li><strong>复位类型</strong>：分为破坏性复位（如电源-on复位、外部复位等）和功能性复位（如软件复位等），处理流程不同。</li></ul><h3 id="_5-3-启动相关" tabindex="-1">5.3 启动相关 <a class="header-anchor" href="#_5-3-启动相关" aria-label="Permalink to “5.3 启动相关”">​</a></h3><ul><li>涉及TEST闪存、UTEST闪存、Boot Assist Flash（BAF）等内存元素，BAF包含工厂代码辅助启动过程。</li></ul><h2 id="六、其他" tabindex="-1">六、其他 <a class="header-anchor" href="#六、其他" aria-label="Permalink to “六、其他”">​</a></h2><ul><li>文档还包含设备配置格式（DCF）记录、电源管理、安全性、调试支持等内容，以及详细的寄存器描述和功能说明。</li></ul>',36)])])}const S=l(t,[["render",n]]);export{M as __pageData,S as default};
